mapper.update:
UPDATE education
school_name = #{schoolName}, degree = #{degree}, major = #{major}, gpa = #{gpa}, start_date = #{startDate}, end_date = #{endDate}, description = #{description}, achievements = #{achievements}, sort_order = #{sortOrder}, updated_at = NOW()
WHERE id = #{id} AND resume_id = #{resumeId}

mapper.delete:
